void main() {
  int age = 20;
  bool hasPermission = true;

  bool canAccess = age >= 18 && hasPermission;

  if (canAccess) {
    print('Access granted');
  } else {
    print('Access denied');
  }

  String status = canAccess ? 'Allowed' : 'Blocked';
  print('Status: $status');
}
